// Script Continued Below
(function executeRule(current, previous /*null when async*/) {

	if(current.u_wait_for_subtasks_to_finish){
		if(current.u_task_requester != previous.u_task_requester){
			// if the owner of this task changed and any of this task's subtasks are in wait state, then reset thier owner as well
			var grSubTasksClosedIncomplete = new GlideRecord('x_153465_discovert_route_task_instance');
			grSubTasksClosedIncomplete.addQuery('parent', current.getUniqueValue());
			grSubTasksClosedIncomplete.addQuery('u_wait_for_subtasks_to_finish', true);
			grSubTasksClosedIncomplete.query();
			if(grSubTasksClosedIncomplete.next()){
				grSubTasksClosedIncomplete.u_task_requester = current.u_task_requester;
				grSubTasksClosedIncomplete.update();
			}
		}

	}

})(current, previous);
